            size_t p = 0;
            auto condVal = parseExpression(rec.condition, p);
            bool condBool = true;
            if (condVal && !std::holds_alternative<std::monostate>(condVal->value)) {
                if (std::holds_alternative<double>(condVal->value)) condBool = std::get<double>(condVal->value) != 0;
