            std::vector<std::shared_ptr<GemObject>> vo;
            for (auto& e : elements) vo.push_back(std::get<std::shared_ptr<GemObject>>(e->value));
            return std::make_shared<GemValue>(vo);
        } else {
            return std::make_shared<GemValue>(elements);
        }
    }
